```tsx
interface Callback<Result> {
  (error: null, result: Result): void;
  (error: Error, result: null): void;
}
```

then declare the callback directly like this:

```tsx
const logIt: Callback<number> = (err, num) => {
    if (err) {
        console.error(err);
    }
    else {
        console.log(num)
     
  }
}
```

