Should we use overloads instead of `LocalSource` vs `InlineSource` suffixes? Something like (this also removes the `upsert` variant in favor of a `create` arg on select; see comment on `Stack` for more details on this suggestion):

```typescript
export interface LocalProgramArgs {
    stackName: string;
    workDir: string;
}

export interface InlineProgramArgs {
    stackName: string;
    projectName: string;
    program: PulumiFn;
}

export class LocalWorkspace implements Workspace {
    public static createStack(args: LocalProgramArgs, opts?: LocalWorkspaceOpts): Promise<Stack>;
    public static createStack(args: InlineProgramArgs, opts?: LocalWorkspaceOpts): Promise<Stack>;
    static async createStack(args: LocalProgramArgs | InlineProgramArgs, opts?: LocalWorkspaceOpts): Promise<Stack> {
        if (isLocalProgramArgs(args)) {
            // Local implementation...
        } else if (isInlineProgramArgs(args)) {
            // Inline implementation...
        } else {
            throw new Error(`Unexpected args: ${args}`);
        }
    }

    public static selectStack(args: LocalProgramArgs, create?: boolean, opts?: LocalWorkspaceOpts): Promise<Stack>;
    public static selectStack(args: InlineProgramArgs, create?: boolean, opts?: LocalWorkspaceOpts): Promise<Stack>;
    static async selectStack(args: LocalProgramArgs | InlineProgramArgs, create = false, opts?: LocalWorkspaceOpts): Promise<Stack> {
        if (isLocalProgramArgs(args)) {
            // Local implementation...
        } else if (isInlineProgramArgs(args)) {
            // Inline implementation...
        } else {
            throw new Error(`Unexpected args: ${args}`);
        }
    }
}

function isLocalProgramArgs(args: LocalProgramArgs | InlineProgramArgs): args is LocalProgramArgs {
    return (args as LocalProgramArgs).workDir !== undefined;
}

function isInlineProgramArgs(args: LocalProgramArgs | InlineProgramArgs): args is InlineProgramArgs {
    return (args as InlineProgramArgs).projectName !== undefined &&
        (args as InlineProgramArgs).program !== undefined;
}
```

And usage:

```typescript
const program = async () => {
    console.log("hello");
}

const stack = await LocalWorkspace.createStack({
    stackName: "foo",
    projectName: "foo",
    program,
})
```

