**UNTESTED**, but dumping both the warnings and the odd branched definitions of `import_recipe` like this would IMHO be both shorter and more readable:

```
def import_recipe(module, filename):
    filename = os.path.join(os.path.abspath(os.path.dirname(__file__), "recipes", filename)
    if PY2:
        return imp.load_source(module, filename)
    else:
        import importlib.util
        if hasattr(importlib.util, 'module_from_spec'):
            # Python 3.5
            spec = importlib.util.spec_from_file_location(module, filename)
            mod = importlib.util.module_from_spec(spec)
            spec.loader.exec_module(mod)
            return mod
        else:
            # Python 3.3 and 3.4:
            from importlib.machinery import SourceFileLoader
            return SourceFileLoader(module, filename).load_module()
```
